  -- ===== Math (TAC §111.7) — 39 TEKS rows + 1 synthetic =====
  ('math', 5, '5.2A', 'Place value to the billions and decimals to the thousandths', 'Recognize the value of digits in any place from the billions place through the thousandths place. Includes naming, identifying, and comparing place values.', 'cc-fifth-grade-math/cc-5th-place-value-decimals-top', 520, false),
  ('math', 5, '5.2B', 'Compare and order decimals to the thousandths', 'Compare and order decimals through the thousandths using the symbols >, <, and =, and using comparative language in real-world contexts.', 'cc-fifth-grade-math/cc-5th-decimals-place-value', 521, false),
  ('math', 5, '5.2C', 'Round decimals to tenths or hundredths', 'Round decimals to tenths or hundredths using a number line, place value, or estimation.', 'cc-fifth-grade-math/cc-5th-decimals-place-value', 522, false),
  ('math', 5, '5.3A', 'Estimate to determine reasonable solutions', 'Estimate to determine solutions to mathematical and real-world problems involving addition, subtraction, multiplication, or division. Identify when to round, truncate, or use compatible numbers.', 'cc-fifth-grade-math/cc-5th-decimal-place-value', 530, false),
  ('math', 5, '5.3B', 'Multiply 3-digit by 2-digit using the standard algorithm', 'Multiply with fluency a three-digit number by a two-digit number using the standard algorithm.', 'cc-fifth-grade-math/cc-5th-multi-digit-mult', 531, false),
  ('math', 5, '5.3C', 'Solve up to 4-digit by 2-digit division using strategies', 'Solve with proficiency for quotients of up to a four-digit dividend by a two-digit divisor using strategies and the standard algorithm.', 'cc-fifth-grade-math/cc-5th-multi-digit-division', 532, false),
  ('math', 5, '5.3D', 'Decimal × whole number with area models', 'Represent multiplication of decimals with products to the hundredths using objects and pictorial models, including area models.', 'cc-fifth-grade-math/cc-5th-mult-div-decimals', 533, false),
  ('math', 5, '5.3E', 'Multiply decimals to hundredths', 'Solve for products of decimals to the hundredths, including situations involving money, using strategies based on place value, properties of operations, and the relationship to whole-number multiplication.', 'cc-fifth-grade-math/cc-5th-mult-div-decimals', 534, false),
  ('math', 5, '5.3F', 'Decimal ÷ whole number with area models', 'Represent quotients of decimals to the hundredths, up to four-digit dividends and two-digit whole-number divisors, using objects and pictorial models, including area models.', 'cc-fifth-grade-math/cc-5th-mult-div-decimals', 535, false),
  ('math', 5, '5.3G', 'Divide decimals to hundredths', 'Solve for quotients of decimals to the hundredths, up to four-digit dividends and two-digit whole-number divisors, using strategies and algorithms, including the standard algorithm.', 'cc-fifth-grade-math/cc-5th-mult-div-decimals', 536, false),
  ('math', 5, '5.3H', 'Add and subtract fractions with unlike denominators', 'Represent and solve addition and subtraction of fractions with unequal denominators referring to the same whole, using objects, pictorial models, and properties of operations.', 'cc-fifth-grade-math/cc-5th-add-sub-fractions', 537, false),
  ('math', 5, '5.3I', 'Multiply a whole number and a fraction', 'Represent and solve multiplication of a whole number and a fraction that refers to the same whole using objects and pictorial models, including area models.', 'cc-fifth-grade-math/cc-5th-mult-frac', 538, false),
  ('math', 5, '5.3J', 'Divide a unit fraction by a whole number and a whole number by a unit fraction', 'Represent division of a unit fraction by a whole number and the division of a whole number by a unit fraction, such as 1/3 ÷ 7 and 7 ÷ 1/3, using objects and pictorial models, including area models.', 'cc-fifth-grade-math/cc-5th-div-frac', 539, false),
  ('math', 5, '5.3K', 'Add and subtract positive rational numbers fluently', 'Add and subtract positive rational numbers fluently. Includes fractions with unlike denominators, mixed numbers with regrouping, and decimals to the thousandths.', 'cc-fifth-grade-math/cc-5th-add-sub-fractions', 540, false),
  ('math', 5, '5.3L', 'Divide whole numbers by unit fractions and unit fractions by whole numbers', 'Divide whole numbers by unit fractions and unit fractions by whole numbers using algorithms.', 'cc-fifth-grade-math/cc-5th-div-frac', 541, false),
  ('math', 5, '5.4A', 'Identify prime and composite numbers', 'Identify prime and composite numbers and recognize the difference between them.', 'cc-fifth-grade-math/cc-5th-factors-multiples', 542, false),
  ('math', 5, '5.4B', 'Multi-step problems with whole numbers using equations with a letter unknown', 'Represent and solve multi-step problems involving the four operations with whole numbers using equations with a letter standing for the unknown quantity.', 'cc-fifth-grade-math/cc-5th-add-sub-decimals-topic', 543, false),
  ('math', 5, '5.4C', 'Generate and graph numerical patterns y = ax or y = x + a', 'Generate a numerical pattern when given a rule in the form y = ax or y = x + a and graph the pattern.', 'cc-fifth-grade-math/cc-5th-coordinate-plane-topic', 544, false),
  ('math', 5, '5.4D', 'Distinguish additive vs multiplicative numerical patterns', 'Recognize the difference between additive and multiplicative numerical patterns given in a table or graph.', 'cc-fifth-grade-math/cc-5th-coordinate-plane-topic', 545, false),
  ('math', 5, '5.4E', 'Meaning of parentheses and brackets', 'Describe the meaning of parentheses and brackets in a numeric expression.', 'cc-fifth-grade-math/cc-5th-arithmetic-operations', 546, false),
  ('math', 5, '5.4F', 'Simplify numerical expressions (no exponents, up to two grouping levels)', 'Simplify numerical expressions that do not involve exponents, including up to two levels of grouping.', 'cc-fifth-grade-math/cc-5th-arithmetic-operations', 547, false),
  ('math', 5, '5.4G', 'Develop volume formulas for rectangular prisms', 'Use concrete objects and pictorial models to develop the formulas for the volume of a rectangular prism, including the special form for a cube (V = l × w × h, V = s × s × s, and V = Bh).', 'cc-fifth-grade-math/cc-5th-volume', 548, false),
  ('math', 5, '5.4H', 'Solve perimeter, area, and volume problems', 'Represent and solve problems related to perimeter and/or area and related to volume.', 'cc-fifth-grade-math/cc-5th-volume', 549, false),
  ('math', 5, '5.5A', 'Classify 2D figures in a hierarchy', 'Classify two-dimensional figures in a hierarchy of sets and subsets using graphic organizers based on their attributes and properties.', 'cc-fifth-grade-math/cc-5th-properties-of-shapes', 550, false),
  ('math', 5, '5.review.factors', 'Factors and multiples (review from Grade 4)', 'Identify factor pairs, list factors of a number, identify multiples, and recognize the relationship between factors and multiples. Reviewed in Grade 5 as a foundation for prime/composite work in 5.4(A) and for fraction equivalence work.', 'cc-fifth-grade-math/cc-5th-factors-multiples', 559, true),
  ('math', 5, '5.6A', 'Volume as unit cubes filling a 3D figure', 'Recognize a cube with side length of one unit as a unit cube having one cubic unit of volume, and the volume of a three-dimensional figure as the number of unit cubes (n cubic units) needed to fill it with no gaps or overlaps.', 'cc-fifth-grade-math/cc-5th-volume', 560, false),
  ('math', 5, '5.6B', 'Volume of rectangular prisms via layers', 'Determine the volume of a rectangular prism with whole-number side lengths in problems related to the number of layers times the number of unit cubes in the area of the base.', 'cc-fifth-grade-math/cc-5th-volume', 561, false),
  ('math', 5, '5.7A', 'Measurement conversions within a system', 'Solve problems by calculating conversions within a measurement system, customary or metric.', 'cc-fifth-grade-math/cc-5th-units-of-measurement', 570, false),
  ('math', 5, '5.8A', 'Key attributes of the coordinate plane', 'Describe the key attributes of the coordinate plane, including perpendicular number lines (axes) where the intersection (origin) is at (0, 0); the x-coordinate as horizontal movement from the origin and the y-coordinate as vertical.', 'cc-fifth-grade-math/cc-5th-coordinate-plane', 580, false),
  ('math', 5, '5.8B', 'Process for graphing ordered pairs in Q1', 'Describe the process for graphing ordered pairs of numbers in the first quadrant of the coordinate plane.', 'cc-fifth-grade-math/cc-5th-coordinate-plane', 581, false),
  ('math', 5, '5.8C', 'Graph ordered pairs in Q1 from real-world or input/output situations', 'Graph in the first quadrant ordered pairs of numbers arising from mathematical and real-world problems, including those generated by number patterns or found in an input-output table.', 'cc-fifth-grade-math/cc-5th-coordinate-plane', 582, false),
  ('math', 5, '5.9A', 'Bar graphs, frequency tables, dot plots, stem-and-leaf', 'Represent categorical data with bar graphs or frequency tables and numerical data, including data sets of measurements in fractions or decimals, with dot plots or stem-and-leaf plots.', 'cc-fifth-grade-math/cc-5th-data', 590, false),
  ('math', 5, '5.9B', 'Discrete paired data on a scatterplot', 'Represent discrete paired data on a scatterplot.', 'cc-fifth-grade-math/cc-5th-data', 591, false),
  ('math', 5, '5.9C', 'Solve 1- and 2-step problems from data displays', 'Solve one- and two-step problems using data from a frequency table, dot plot, bar graph, stem-and-leaf plot, or scatterplot.', 'cc-fifth-grade-math/cc-5th-data', 592, false),
  ('math', 5, '5.10A', 'Define income, payroll, sales, property tax', 'Define income tax, payroll tax, sales tax, and property tax.', 'cc-fifth-grade-math/cc-5th-financial-literacy', 600, false),
  ('math', 5, '5.10B', 'Gross income vs net income', 'Explain the difference between gross income and net income.', 'cc-fifth-grade-math/cc-5th-financial-literacy', 601, false),
  ('math', 5, '5.10C', 'Methods of payment: cash, check, debit, credit, electronic', 'Identify the advantages and disadvantages of different methods of payment, including check, credit card, debit card, and electronic payments.', 'cc-fifth-grade-math/cc-5th-financial-literacy', 602, false),
  ('math', 5, '5.10D', 'Keep and use simple financial records', 'Develop a system for keeping and using financial records.', 'cc-fifth-grade-math/cc-5th-financial-literacy', 603, false),
  ('math', 5, '5.10E', 'Balance a budget when expenses exceed income', 'Describe actions that might be taken to balance a budget when expenses exceed income.', 'cc-fifth-grade-math/cc-5th-financial-literacy', 604, false),
  ('math', 5, '5.10F', 'Balance a simple budget', 'Balance a simple budget.', 'cc-fifth-grade-math/cc-5th-financial-literacy', 605, false),

  -- ===== Reading (TAC §110.7 — vocab, comprehension, response, multiple genres, author's craft) — 22 rows =====
  ('reading', 5, '5.2A', 'Use a dictionary, glossary, or thesaurus', 'Look up unfamiliar words in a dictionary, glossary, or thesaurus to clarify meaning, pronunciation, syllabication, parts of speech, and word origin.', 'ela/cc-5th-reading-vocab', 520, false),
  ('reading', 5, '5.2B', 'Use context clues to determine word meaning', 'Use context within and beyond a sentence — definitions, restatements, examples, contrasts — to determine the meaning of unfamiliar or multiple-meaning words.', 'ela/cc-5th-reading-vocab', 521, false),
  ('reading', 5, '5.2C', 'Affixes and Greek/Latin roots', 'Identify the meaning of and use words with affixes (trans-, super-, -ive, -logy) and Greek/Latin roots (chrono, sphere) to determine word meanings.', 'ela/cc-5th-reading-vocab', 522, false),
  ('reading', 5, '5.6C', 'Make and confirm predictions', 'Make and confirm predictions using text features and the structure of the text.', 'ela/cc-5th-reading-vocab', 560, false),
  ('reading', 5, '5.6F', 'Make inferences with text evidence', 'Make inferences and use evidence to support understanding.', 'ela/cc-5th-reading-vocab', 561, false),
  ('reading', 5, '5.6G', 'Identify key ideas to determine central message', 'Evaluate details read to determine key ideas.', 'ela/cc-5th-reading-vocab', 562, false),
  ('reading', 5, '5.6H', 'Synthesize information across texts', 'Synthesize information from multiple sources to create new understanding.', 'ela/cc-5th-reading-vocab', 563, false),
  ('reading', 5, '5.7C', 'Use text evidence to support a response', 'Use text evidence to support an appropriate response, including direct quotes and paraphrases.', 'ela/cc-5th-reading-vocab', 570, false),
  ('reading', 5, '5.7D', 'Retell, paraphrase, or summarize while preserving meaning', 'Retell, paraphrase, or summarize texts in ways that maintain meaning and logical order.', 'ela/cc-5th-reading-vocab', 571, false),
  ('reading', 5, '5.7G', 'Discuss specific ideas important to meaning', 'Discuss specific ideas in the text that are important to the meaning.', 'ela/cc-5th-reading-vocab', 572, false),
  ('reading', 5, '5.8A', 'Infer multiple themes within and across texts', 'Infer multiple themes within and across texts using text evidence.', 'ela/cc-5th-reading-vocab', 580, false),
  ('reading', 5, '5.8B', 'Analyze character relationships and conflicts', 'Analyze the relationships of and conflicts among the characters.', 'ela/cc-5th-reading-vocab', 581, false),
  ('reading', 5, '5.8C', 'Analyze plot elements (rising action, climax, falling action, resolution)', 'Analyze plot elements, including the rising action, climax, falling action, and resolution.', 'ela/cc-5th-reading-vocab', 582, false),
  ('reading', 5, '5.8D', 'Analyze influence of setting on plot', 'Analyze the influence of the setting, including historical and cultural settings, on the plot.', 'ela/cc-5th-reading-vocab', 583, false),
  ('reading', 5, '5.9A', 'Genre characteristics of children''s literature', 'Demonstrate knowledge of distinguishing characteristics of well-known children''s literature genres including fairy tales, folktales, fables, legends, myths, tall tales, and modern fantasy.', 'ela/cc-5th-reading-vocab', 590, false),
  ('reading', 5, '5.9B', 'Sound devices, figurative language, poet vs speaker', 'Explain the use of sound devices and figurative language and distinguish between the poet and the speaker in a poem.', 'ela/cc-5th-reading-vocab', 591, false),
  ('reading', 5, '5.9D.i', 'Informational: central idea and supporting evidence', 'Recognize characteristics and structures of informational text, including the central idea with supporting evidence.', 'ela/cc-5th-reading-vocab', 592, false),
  ('reading', 5, '5.9D.ii', 'Informational: features and graphics', 'Identify text features (bold, italics, headings, captions) and graphics (charts, maps, diagrams) and explain how they contribute to meaning.', 'ela/cc-5th-reading-vocab', 593, false),
  ('reading', 5, '5.9D.iii', 'Informational: text structures', 'Identify organizational patterns of informational text — compare-contrast, cause-effect, problem-solution, or sequential order.', 'ela/cc-5th-reading-vocab', 594, false),
  ('reading', 5, '5.9E', 'Argumentative: claim and supporting evidence', 'Recognize characteristics and structures of argumentative text by identifying the claim and explaining how the author uses facts, details, and explanations to support the argument.', 'ela/cc-5th-reading-vocab', 595, false),
  ('reading', 5, '5.10A', 'Author''s purpose and message', 'Explain the author''s purpose and message within a text.', 'ela/cc-5th-reading-vocab', 600, false),
  ('reading', 5, '5.10D', 'Imagery and figurative language contribute to meaning', 'Describe how the author''s use of imagery, literal and figurative language — similes, metaphors, hyperbole, personification — contributes to meaning.', 'ela/cc-5th-reading-vocab', 601, false),

  -- ===== Language (TAC §110.7(b)(11) editing strands + a few revising) — 14 rows =====
  ('language', 5, '5.11D.i', 'Subject-verb agreement', 'Edit drafts using standard English conventions, including subject-verb agreement (simple, compound, and with collective nouns).', 'ela/cc-5th-reading-vocab', 700, false),
  ('language', 5, '5.11D.ii', 'Verb tenses including consistency and perfect tenses', 'Edit drafts using verb tenses, including past, present, future, and perfect; maintain tense consistency within a passage.', 'ela/cc-5th-reading-vocab', 701, false),
  ('language', 5, '5.11D.iii', 'Singular, plural, common, proper, possessive nouns', 'Edit drafts using singular, plural, common, proper, and possessive nouns correctly.', 'ela/cc-5th-reading-vocab', 702, false),
  ('language', 5, '5.11D.iv', 'Adjectives, articles, comparative and superlative forms', 'Edit drafts using adjectives and articles, including comparative and superlative forms.', 'ela/cc-5th-reading-vocab', 703, false),
  ('language', 5, '5.11D.v', 'Adverbs (comparative and superlative)', 'Edit drafts using adverbs that convey time, place, manner, frequency, intensity, and degree, including comparative and superlative forms.', 'ela/cc-5th-reading-vocab', 704, false),
  ('language', 5, '5.11D.vi', 'Prepositional phrases as modifiers', 'Edit drafts using prepositions and prepositional phrases that function as adjectives or adverbs.', 'ela/cc-5th-reading-vocab', 705, false),
  ('language', 5, '5.11D.vii', 'Pronouns: subject vs object case, antecedent agreement, reflexive', 'Edit drafts using pronouns — subject, object, possessive, reflexive — with clear antecedent agreement.', 'ela/cc-5th-reading-vocab', 706, false),
  ('language', 5, '5.11D.viii', 'Conjunctions: coordinating, subordinating, correlative', 'Edit drafts using coordinating, subordinating, and correlative conjunctions.', 'ela/cc-5th-reading-vocab', 707, false),
  ('language', 5, '5.11D.ix', 'Capitalization', 'Edit drafts using capitalization for proper nouns, titles of works, abbreviations, and the first word of a sentence or quotation.', 'ela/cc-5th-reading-vocab', 708, false),
  ('language', 5, '5.11D.x', 'Punctuation: commas in compound and complex sentences, dialogue, quotation marks', 'Edit drafts using punctuation, including commas in compound and complex sentences, quotation marks in dialogue, apostrophes in contractions and possessives.', 'ela/cc-5th-reading-vocab', 709, false),
  ('language', 5, '5.11D.xi', 'Spelling: commonly confused words, suffixes, syllabication', 'Edit drafts using correct spelling of commonly confused words (homophones), words with affixes, and multisyllabic words.', 'ela/cc-5th-reading-vocab', 710, false),
  ('language', 5, '5.11C.i', 'Combining sentences for clarity', 'Revise drafts to combine related sentences using a variety of conjunctions and clauses for clarity and concision.', 'ela/cc-5th-reading-vocab', 720, false),
  ('language', 5, '5.11C.ii', 'Sentence boundaries: fragments and run-ons', 'Revise drafts to fix sentence fragments and run-on sentences using punctuation and rewording.', 'ela/cc-5th-reading-vocab', 721, false),
  ('language', 5, '5.11C.iii', 'Complete simple, compound, and complex sentences', 'Revise drafts to produce complete simple, compound, and complex sentences with appropriate punctuation.', 'ela/cc-5th-reading-vocab', 722, false)
